// ── Style helpers ─────────────────────────────────────────────────────────────

func runStatusIcon(status string) string {
	switch status {
	case "completed":
		return "lucide--check-circle-2"
	case "aborted":
		return "lucide--ban"
	case "failed":
		return "lucide--alert-circle"
	case "awaiting_human":
		return "lucide--user-check"
	case "running":
		return "lucide--loader-2"
	default:
		return "lucide--clock"
	}
}

func runStatusIconColor(status string) string {
	switch status {
	case "completed":
		return "text-success"
	case "aborted", "failed":
		return "text-error"
	case "awaiting_human":
		return "text-warning"
	case "running":
		return "text-primary animate-spin"
	default:
		return "text-base-content/40"
	}
}

func runStatusLabel(status string) string {
	switch status {
	case "pending":
		return "Pending"
	case "running":
		return "Running"
	case "awaiting_human":
		return "Awaiting Review"
	case "completed":
		return "Completed"
	case "aborted":
		return "Aborted"
	case "failed":
		return "Failed"
	default:
		return status
	}
}

func runStatusBadgeClass(status string) string {
	switch status {
	case "completed":
		return "badge-success"
	case "aborted", "failed":
		return "badge-error"
	case "awaiting_human":
		return "badge-warning"
	case "running":
		return "badge-info"
	default:
		return "badge-ghost"
	}
}

func runStepLabel(name string) string {
	switch name {
	case "draft_assessment":
		return "Draft Assessment"
	case "draft_calibration":
		return "Draft Calibration"
	case "apply_calibration":
		return "Apply Calibration"
	case "snapshot_cycle":
		return "Snapshot Cycle"
	default:
		return name
	}
}

func runStepBorderClass(status string) string {
	switch status {
	case "done":
		return "border-success/20 bg-success/5"
	case "running":
		return "border-primary/30 bg-primary/5"
	case "awaiting_human":
		return "border-warning/30 bg-warning/5"
	case "failed":
		return "border-error/20 bg-error/5"
	default:
		return "border-base-content/10 bg-base-100 opacity-60"
	}
}

func runStepCircleClass(status string) string {
	switch status {
	case "done":
		return "bg-success text-success-content"
	case "running":
		return "bg-primary text-primary-content"
	case "awaiting_human":
		return "bg-warning text-warning-content"
	case "failed":
		return "bg-error text-error-content"
	default:
		return "bg-base-content/10 text-base-content/40"
	}
}

func runStepLabelClass(status string) string {
	switch status {
	case "done":
		return "text-success"
	case "running":
		return "text-primary"
	case "awaiting_human":
		return "text-warning"
	case "failed":
		return "text-error"
	default:
		return "text-base-content/40"
	}
}

